# Explorer · S48-T1-A-E1: ranking por similitud (dot) al top esperado
record = {"case_id": "CASO-PUN-048-1A", "query": [1.0, 0.0], "docs": {"d1": [0.8, 0.2], "d2": [0.1, 0.9]}, "metric": "dot", "version": "emb-v2", "expected_top": "d1"}

def _score(k):
    return sum(a * b for a, b in zip(record["query"], record["docs"][k]))

meets_contract = max(record["docs"], key=_score) == record["expected_top"]
status = "PASS" if meets_contract else "REJECT_EMBEDDING_RANK"
print("S48-T1-A", status)

